m=pow(c,d,n)
def num2str(num):
    tmp = hex(num)[2:]
    # 如果长度为奇数，前面补0
    if len(tmp) % 2 != 0:
        tmp = '0' + tmp
    # 使用 bytes.fromhex() 替代 decode("hex")
    return bytes.fromhex(tmp)

print(num2str(m))

